alter table public.course_lessons
add column if not exists type text not null default 'lesson',
add column if not exists objective text,
add column if not exists checklist text[] not null default '{}';

drop policy if exists "Users can add own achievements" on public.user_achievements;
create policy "Users can add own achievements"
on public.user_achievements for insert
to authenticated
with check ((select auth.uid()) = profile_id);

insert into public.skills (id, name)
values
  ('91000000-0000-4000-8000-000000000001', 'HTML'),
  ('91000000-0000-4000-8000-000000000002', 'CSS')
on conflict (id) do update set
  name = excluded.name;

insert into public.achievements (id, title, description, icon)
values (
  '90000000-0000-4000-8000-000000000001',
  'HTML & CSS Foundation Builder',
  'Completed HTML & CSS Foundations and built a responsive SaaS landing page.',
  'layout-template'
)
on conflict (id) do update set
  title = excluded.title,
  description = excluded.description,
  icon = excluded.icon;

insert into public.courses (
  id,
  slug,
  title,
  description,
  category,
  level,
  duration_minutes,
  lessons_count,
  xp_reward,
  rating,
  students_count,
  icon,
  color,
  is_published
) values (
  '10000000-0000-4000-8000-000000000001',
  'html-css-foundations',
  'HTML & CSS Foundations',
  'A complete beginner-friendly course for learning real HTML and CSS foundations through theory, practice, mini projects and a final responsive SaaS landing page.',
  'Frontend',
  'Beginner',
  1800,
  91,
  3000,
  4.9,
  0,
  'code',
  'blue',
  true
) on conflict (slug) do update set
  title = excluded.title,
  description = excluded.description,
  category = excluded.category,
  level = excluded.level,
  duration_minutes = excluded.duration_minutes,
  lessons_count = excluded.lessons_count,
  xp_reward = excluded.xp_reward,
  rating = excluded.rating,
  students_count = excluded.students_count,
  icon = excluded.icon,
  color = excluded.color,
  is_published = excluded.is_published,
  updated_at = now();

insert into public.course_modules (id, course_id, title, description, position)
values
  ('20000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000001', 'Web Foundations', 'Understand how websites work, how project files fit together and how to create your first HTML/CSS page.', 1),
  ('20000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000001', 'HTML Fundamentals', 'Learn the core HTML tags used on real websites and organize clean page content.', 2),
  ('20000000-0000-4000-8000-000000000003', '10000000-0000-4000-8000-000000000001', 'Semantic HTML', 'Write meaningful HTML that improves accessibility, SEO and maintainability.', 3),
  ('20000000-0000-4000-8000-000000000004', '10000000-0000-4000-8000-000000000001', 'CSS Fundamentals', 'Style pages from scratch using selectors, colors, typography, spacing and units.', 4),
  ('20000000-0000-4000-8000-000000000005', '10000000-0000-4000-8000-000000000001', 'Box Model', 'Understand the layout foundation behind content, padding, borders, margins and display behavior.', 5),
  ('20000000-0000-4000-8000-000000000006', '10000000-0000-4000-8000-000000000001', 'Flexbox', 'Build clean horizontal and vertical layouts with modern flex patterns.', 6),
  ('20000000-0000-4000-8000-000000000007', '10000000-0000-4000-8000-000000000001', 'CSS Grid', 'Create larger responsive layouts and card grids with CSS Grid.', 7),
  ('20000000-0000-4000-8000-000000000008', '10000000-0000-4000-8000-000000000001', 'Responsive Design', 'Make pages work well on mobile, tablet and desktop using a mobile-first workflow.', 8),
  ('20000000-0000-4000-8000-000000000009', '10000000-0000-4000-8000-000000000001', 'Forms & UI Components', 'Build real form and UI elements with accessible states and clean structure.', 9),
  ('20000000-0000-4000-8000-000000000010', '10000000-0000-4000-8000-000000000001', 'Modern CSS Patterns', 'Create reusable styles, small design systems, dark mode basics and subtle interactions.', 10),
  ('20000000-0000-4000-8000-000000000011', '10000000-0000-4000-8000-000000000001', 'Final Project: SaaS Landing Page', 'Build a complete responsive landing page for a fictional SaaS application from scratch.', 11)
on conflict (course_id, position) do update set
  title = excluded.title,
  description = excluded.description;

insert into public.course_lessons (
  id,
  course_id,
  module_id,
  title,
  slug,
  summary,
  content,
  position,
  duration_minutes,
  xp_reward,
  is_preview,
  type,
  objective,
  checklist
) values
  ('30000000-0000-4000-8000-000000000001', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000001', 'What is a website?', 'what-is-a-website', 'Understand what a website is and what users actually receive in the browser.', 'Learn how websites are made of files, URLs, requests and browser-rendered documents. Practice explaining the difference between a page, a website and a web app in your own words.', 1, 20, 25, true, 'lesson', 'Understand the basic idea of websites and web pages.', array['Explain what a website is', 'Describe what a browser displays', 'Understand page vs website']),
  ('30000000-0000-4000-8000-000000000002', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000001', 'How browser, HTML, CSS and JavaScript work together', 'how-browser-html-css-javascript-work-together', 'Learn the role of each core frontend technology.', 'HTML gives structure, CSS controls presentation and JavaScript adds behavior. This lesson explains how the browser loads and combines them into one visual experience.', 2, 25, 30, false, 'lesson', 'Understand the responsibilities of HTML, CSS and JavaScript.', array['Know what HTML does', 'Know what CSS does', 'Know what JavaScript does']),
  ('30000000-0000-4000-8000-000000000003', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000001', 'Files, folders and project structure', 'files-folders-and-project-structure', 'Create clean project folders from the first day.', 'You will organize an HTML/CSS project with index.html, styles.css, images and assets folders. The goal is to make your project easy to understand and maintain.', 3, 25, 30, false, 'lesson', 'Set up a clean frontend project structure.', array['Create index.html', 'Create styles.css', 'Create assets folder']),
  ('30000000-0000-4000-8000-000000000004', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000001', 'VS Code basics', 'vs-code-basics', 'Learn basic editor workflow for frontend development.', 'Set up VS Code, open folders, create files, use indentation, format code and navigate between project files without friction.', 4, 25, 30, false, 'lesson', 'Use VS Code comfortably for basic frontend work.', array['Open project folder', 'Create files', 'Format HTML and CSS']),
  ('30000000-0000-4000-8000-000000000005', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000001', 'First HTML document', 'first-html-document', 'Write your first valid HTML document.', 'Create the basic HTML skeleton with doctype, html, head, title and body. You will understand which parts are visible and which parts describe the page.', 5, 30, 35, false, 'lesson', 'Create a valid first HTML page.', array['Add doctype', 'Add head and body', 'Set page title']),
  ('30000000-0000-4000-8000-000000000006', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000001', 'Live Server and developer tools', 'live-server-and-developer-tools', 'Preview pages locally and inspect them in the browser.', 'Use Live Server for fast refresh and DevTools to inspect HTML, CSS and layout. This starts the debugging workflow you will use throughout the course.', 6, 30, 35, false, 'lesson', 'Preview and inspect your work locally.', array['Run Live Server', 'Open DevTools', 'Inspect an element']),
  ('30000000-0000-4000-8000-000000000007', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000001', 'Exercise: Create your first page', 'exercise-create-your-first-page', 'Create index.html and styles.css with basic content.', 'Build a first page with a heading, paragraph, image and link. Keep files organized and connect the CSS file correctly. This is your first complete mini workflow.', 7, 60, 70, false, 'exercise', 'Create your first connected HTML and CSS page.', array['Create index.html', 'Create styles.css', 'Add heading', 'Add paragraph', 'Add image', 'Add link']),

  ('30000000-0000-4000-8000-000000000008', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', 'HTML document structure', 'html-document-structure', 'Understand the standard structure of an HTML file.', 'Learn how doctype, html, head, meta, title and body work together. You will build documents that are predictable, valid and easy to extend.', 1, 25, 30, false, 'lesson', 'Understand the required parts of an HTML document.', array['Use doctype', 'Use meta charset', 'Use viewport meta tag']),
  ('30000000-0000-4000-8000-000000000009', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', 'Headings and paragraphs', 'headings-and-paragraphs', 'Structure text content with headings and paragraphs.', 'Use h1 to h6 and p tags correctly. Learn why heading hierarchy matters for readability, accessibility and SEO.', 2, 25, 30, false, 'lesson', 'Write clean text structure with headings and paragraphs.', array['Use one h1', 'Create heading hierarchy', 'Write readable paragraphs']),
  ('30000000-0000-4000-8000-000000000010', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', 'Links and navigation', 'links-and-navigation', 'Create links between pages and external websites.', 'Use anchor tags, href values, relative paths and navigation lists. Learn when links should open pages and how users move through websites.', 3, 30, 35, false, 'lesson', 'Create useful links and basic navigation.', array['Use anchor tags', 'Use relative links', 'Create nav links']),
  ('30000000-0000-4000-8000-000000000011', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', 'Images and alt text', 'images-and-alt-text', 'Add images responsibly and accessibly.', 'Use img src and alt text. Learn what makes alt text helpful and when decorative images should have empty alt text.', 4, 30, 35, false, 'lesson', 'Add images with useful alt text.', array['Add image', 'Write alt text', 'Understand decorative images']),
  ('30000000-0000-4000-8000-000000000012', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', 'Lists', 'lists', 'Use ordered, unordered and nested lists.', 'Build lists for skills, steps, navigation and grouped content. Learn when ul, ol and li are the right choice.', 5, 25, 30, false, 'lesson', 'Use lists for grouped content.', array['Create ul list', 'Create ol list', 'Use li correctly']),
  ('30000000-0000-4000-8000-000000000013', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', 'Buttons', 'buttons', 'Understand the button element and common usage.', 'Learn what buttons are for, how they differ from links and why clear labels matter. You will prepare for real UI components later.', 6, 20, 25, false, 'lesson', 'Use button elements for actions.', array['Create button', 'Use clear label', 'Know link vs button basics']),
  ('30000000-0000-4000-8000-000000000014', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', 'Divs and spans', 'divs-and-spans', 'Use generic containers without overusing them.', 'Learn the difference between block and inline generic elements. Use div and span only when semantic elements are not a better fit.', 7, 25, 30, false, 'lesson', 'Use generic containers correctly.', array['Use div for grouping', 'Use span for inline styling', 'Avoid div-only structure']),
  ('30000000-0000-4000-8000-000000000015', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', 'Comments and clean structure', 'comments-and-clean-structure', 'Keep HTML readable for yourself and others.', 'Use indentation, comments and consistent structure. Learn how clean HTML makes CSS easier to write and debug.', 8, 25, 30, false, 'lesson', 'Write readable HTML structure.', array['Indent nested elements', 'Use comments sparingly', 'Group related content']),
  ('30000000-0000-4000-8000-000000000016', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000002', 'Exercise: Build a personal profile page', 'exercise-build-a-personal-profile-page', 'Create a simple profile page with real content blocks.', 'Build a page with your name, short bio, skills list, profile image and social links. The focus is clean HTML before advanced styling.', 9, 75, 80, false, 'exercise', 'Build a complete profile page structure.', array['Add name', 'Add bio', 'Add skills list', 'Add profile image', 'Add social links']),

  ('30000000-0000-4000-8000-000000000017', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000003', 'Why semantic HTML matters', 'why-semantic-html-matters', 'Learn why meaning matters in HTML.', 'Semantic HTML helps browsers, screen readers, search engines and developers understand the page. You will learn to choose elements by purpose, not appearance.', 1, 25, 30, false, 'lesson', 'Understand the value of semantic HTML.', array['Define semantic HTML', 'Know benefits', 'Avoid div-only markup']),
  ('30000000-0000-4000-8000-000000000018', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000003', 'header, main, section, article, footer', 'semantic-layout-elements', 'Use major layout landmarks correctly.', 'Build pages with header, main, section, article and footer. Learn how each element communicates the role of a page region.', 2, 35, 40, false, 'lesson', 'Use core semantic layout elements.', array['Use header', 'Use main', 'Use section', 'Use article', 'Use footer']),
  ('30000000-0000-4000-8000-000000000019', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000003', 'nav and accessible navigation', 'nav-and-accessible-navigation', 'Create navigation that is clear and accessible.', 'Use nav for groups of important links. Learn naming, link text, active states and keyboard-friendly navigation basics.', 3, 30, 35, false, 'lesson', 'Create accessible navigation structure.', array['Use nav element', 'Use clear link text', 'Support keyboard navigation']),
  ('30000000-0000-4000-8000-000000000020', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000003', 'Forms and labels', 'forms-and-labels', 'Understand the foundation of accessible forms.', 'Use form, label and input together. Learn why labels are required and how they improve usability for everyone.', 4, 30, 35, false, 'lesson', 'Build accessible form structure.', array['Use form', 'Connect labels to inputs', 'Avoid placeholder-only labels']),
  ('30000000-0000-4000-8000-000000000021', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000003', 'inputs, textarea, select', 'inputs-textarea-select', 'Use common form fields correctly.', 'Learn when to use text inputs, email inputs, password inputs, textarea and select. You will create forms that match real user data.', 5, 35, 40, false, 'lesson', 'Choose correct form controls.', array['Use input types', 'Use textarea', 'Use select']),
  ('30000000-0000-4000-8000-000000000022', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000003', 'buttons vs links', 'buttons-vs-links', 'Choose the correct element for actions and navigation.', 'Links move users somewhere. Buttons perform actions. Learn this distinction because it affects accessibility, semantics and future JavaScript behavior.', 6, 25, 30, false, 'lesson', 'Know when to use a link and when to use a button.', array['Use links for navigation', 'Use buttons for actions', 'Avoid clickable divs']),
  ('30000000-0000-4000-8000-000000000023', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000003', 'Basic accessibility', 'basic-accessibility', 'Learn beginner accessibility habits.', 'Accessibility starts with semantic HTML, labels, alt text, color contrast and keyboard navigation. You will build habits that prevent common beginner mistakes.', 7, 35, 40, false, 'lesson', 'Apply basic accessibility principles.', array['Use semantic structure', 'Label forms', 'Check contrast', 'Keep keyboard access']),
  ('30000000-0000-4000-8000-000000000024', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000003', 'SEO basics', 'seo-basics', 'Understand how HTML supports search engines.', 'Learn title tags, meta descriptions, heading structure, link text and meaningful content. This is not advanced SEO, but it gives you correct foundations.', 8, 30, 35, false, 'lesson', 'Use HTML basics that support SEO.', array['Set page title', 'Use headings well', 'Write meaningful links']),
  ('30000000-0000-4000-8000-000000000025', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000003', 'Exercise: Build a blog article page', 'exercise-build-a-blog-article-page', 'Create a semantic article page.', 'Build a blog page with header, nav, article, author section, related posts and footer. The goal is professional semantic structure.', 9, 85, 90, false, 'exercise', 'Build a semantic blog article page.', array['Add header', 'Add nav', 'Add article', 'Add author section', 'Add related posts', 'Add footer']),

  ('30000000-0000-4000-8000-000000000026', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000004', 'How CSS works', 'how-css-works', 'Understand how CSS is loaded and applied.', 'Learn inline, internal and external CSS, the cascade and why external stylesheets are the normal project setup.', 1, 30, 35, false, 'lesson', 'Understand how CSS connects to HTML.', array['Link stylesheet', 'Understand cascade basics', 'Use external CSS']),
  ('30000000-0000-4000-8000-000000000027', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000004', 'Selectors', 'selectors', 'Target elements with CSS selectors.', 'Use element, class, descendant and grouped selectors. Learn why classes are the main styling hook in maintainable CSS.', 2, 35, 40, false, 'lesson', 'Use common CSS selectors.', array['Use element selector', 'Use class selector', 'Use grouped selectors']),
  ('30000000-0000-4000-8000-000000000028', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000004', 'Colors', 'colors', 'Apply color intentionally.', 'Use named colors, hex, rgb and hsl. Learn simple color roles for background, text, border and accent states.', 3, 30, 35, false, 'lesson', 'Use CSS colors clearly.', array['Set text color', 'Set background color', 'Use accent color']),
  ('30000000-0000-4000-8000-000000000029', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000004', 'Typography', 'typography', 'Style readable text.', 'Learn font-family, font-weight and text styling. You will focus on readability instead of decorative styling.', 4, 35, 40, false, 'lesson', 'Style typography for readable pages.', array['Set font family', 'Set font weight', 'Improve readability']),
  ('30000000-0000-4000-8000-000000000030', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000004', 'Font sizes and line height', 'font-sizes-and-line-height', 'Control text scale and vertical rhythm.', 'Learn how font-size and line-height affect reading comfort. Build a simple heading and paragraph scale.', 5, 30, 35, false, 'lesson', 'Create readable type scale basics.', array['Set font size', 'Set line height', 'Create heading scale']),
  ('30000000-0000-4000-8000-000000000031', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000004', 'Spacing: margin and padding', 'spacing-margin-and-padding', 'Create clean spacing around and inside elements.', 'Learn the difference between margin and padding. You will use spacing to make content feel organized and readable.', 6, 35, 40, false, 'lesson', 'Use margin and padding correctly.', array['Use margin for outside spacing', 'Use padding for inside spacing', 'Avoid random spacing']),
  ('30000000-0000-4000-8000-000000000032', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000004', 'Borders and radius', 'borders-and-radius', 'Use borders and rounded corners for UI structure.', 'Style cards, buttons and images with borders and border-radius. Learn how subtle borders improve separation.', 7, 25, 30, false, 'lesson', 'Use borders and radius for UI elements.', array['Add border', 'Set border radius', 'Create card edges']),
  ('30000000-0000-4000-8000-000000000033', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000004', 'Backgrounds', 'backgrounds', 'Style sections with backgrounds.', 'Use background-color, simple gradients and background images carefully. Learn how backgrounds affect contrast and readability.', 8, 30, 35, false, 'lesson', 'Use backgrounds without hurting readability.', array['Set background color', 'Use simple gradient', 'Maintain contrast']),
  ('30000000-0000-4000-8000-000000000034', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000004', 'CSS units: px, %, rem, vh, vw', 'css-units-px-percent-rem-vh-vw', 'Choose practical CSS units.', 'Learn when to use px, percent, rem, viewport width and viewport height. You will avoid common sizing mistakes.', 9, 35, 40, false, 'lesson', 'Choose CSS units for common layout needs.', array['Use px for small fixed values', 'Use rem for scalable spacing', 'Use percent and viewport units']),
  ('30000000-0000-4000-8000-000000000035', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000004', 'Exercise: Style your profile page', 'exercise-style-your-profile-page', 'Apply CSS fundamentals to your profile page.', 'Style your previous profile page with colors, fonts, spacing, buttons and cards. The result should look like a simple personal website.', 10, 90, 95, false, 'exercise', 'Turn the profile HTML into a styled page.', array['Add colors', 'Set fonts', 'Improve spacing', 'Style buttons', 'Create card layout']),

  ('30000000-0000-4000-8000-000000000036', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000005', 'Content, padding, border, margin', 'content-padding-border-margin', 'Understand the full CSS box model.', 'Every element is a box. Learn how content, padding, border and margin combine to create real layout space.', 1, 35, 40, false, 'lesson', 'Understand the box model parts.', array['Identify content area', 'Identify padding', 'Identify border', 'Identify margin']),
  ('30000000-0000-4000-8000-000000000037', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000005', 'box-sizing: border-box', 'box-sizing-border-box', 'Make sizing easier with border-box.', 'Learn why border-box is used in modern CSS resets and how it makes width calculations predictable.', 2, 25, 30, false, 'lesson', 'Use border-box sizing confidently.', array['Understand default sizing', 'Set border-box', 'Predict element width']),
  ('30000000-0000-4000-8000-000000000038', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000005', 'Width and height', 'width-and-height', 'Control element dimensions safely.', 'Use width, max-width, min-height and avoid fixed heights where content should flow naturally.', 3, 30, 35, false, 'lesson', 'Set dimensions without breaking layouts.', array['Use width', 'Use max-width', 'Avoid unnecessary fixed height']),
  ('30000000-0000-4000-8000-000000000039', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000005', 'Overflow', 'overflow', 'Handle content that does not fit.', 'Learn overflow visible, hidden, auto and scroll. Use DevTools to see when content escapes its container.', 4, 25, 30, false, 'lesson', 'Handle overflowing content.', array['Identify overflow', 'Use overflow hidden', 'Use overflow auto']),
  ('30000000-0000-4000-8000-000000000040', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000005', 'Display block, inline, inline-block', 'display-block-inline-inline-block', 'Understand basic display behavior.', 'Learn how block, inline and inline-block elements behave. This makes spacing and sizing much less confusing.', 5, 35, 40, false, 'lesson', 'Understand basic display values.', array['Know block behavior', 'Know inline behavior', 'Use inline-block']),
  ('30000000-0000-4000-8000-000000000041', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000005', 'Debugging layout with DevTools', 'debugging-layout-with-devtools', 'Use DevTools to inspect box model issues.', 'Open DevTools, inspect spacing, toggle CSS rules and debug layout visually instead of guessing.', 6, 35, 40, false, 'lesson', 'Debug box model issues with DevTools.', array['Inspect element', 'Read box model panel', 'Toggle CSS rules']),
  ('30000000-0000-4000-8000-000000000042', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000005', 'Exercise: Build pricing cards', 'exercise-build-pricing-cards', 'Build three pricing plans with clean box model spacing.', 'Create 3 pricing cards with spacing, borders, badges and buttons. Focus on consistent dimensions and clear visual hierarchy.', 7, 90, 95, false, 'exercise', 'Build pricing cards using box model fundamentals.', array['Create 3 cards', 'Use padding and margins', 'Add borders', 'Add badges', 'Add buttons']),

  ('30000000-0000-4000-8000-000000000043', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000006', 'display: flex', 'display-flex', 'Start using Flexbox.', 'Learn what happens when a parent becomes a flex container and how children become flex items.', 1, 30, 35, false, 'lesson', 'Understand the flex container and flex items.', array['Set display flex', 'Identify main axis', 'Identify cross axis']),
  ('30000000-0000-4000-8000-000000000044', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000006', 'flex-direction', 'flex-direction', 'Control the main axis.', 'Use row and column layouts. Learn how direction changes alignment behavior.', 2, 25, 30, false, 'lesson', 'Control flex direction.', array['Use row', 'Use column', 'Understand axis change']),
  ('30000000-0000-4000-8000-000000000045', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000006', 'justify-content', 'justify-content', 'Align items on the main axis.', 'Use justify-content for spacing and alignment in rows and columns. Practice common nav and button layouts.', 3, 30, 35, false, 'lesson', 'Align flex items on the main axis.', array['Use center', 'Use space-between', 'Use flex-start']),
  ('30000000-0000-4000-8000-000000000046', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000006', 'align-items', 'align-items', 'Align items on the cross axis.', 'Use align-items to center content vertically, stretch rows and align card content.', 4, 30, 35, false, 'lesson', 'Align flex items on the cross axis.', array['Use center', 'Use stretch', 'Understand cross axis']),
  ('30000000-0000-4000-8000-000000000047', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000006', 'gap', 'gap', 'Create consistent spacing between flex items.', 'Use gap instead of margin hacks. Learn why gap makes layouts easier to maintain.', 5, 20, 25, false, 'lesson', 'Use gap for layout spacing.', array['Add row gap', 'Add column gap', 'Avoid margin hacks']),
  ('30000000-0000-4000-8000-000000000048', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000006', 'flex-wrap', 'flex-wrap', 'Allow items to wrap on smaller screens.', 'Use flex-wrap for responsive rows. Learn where wrapping works and where Grid is a better option.', 6, 25, 30, false, 'lesson', 'Use wrapping for responsive flex layouts.', array['Enable wrap', 'Control gaps', 'Test narrow screens']),
  ('30000000-0000-4000-8000-000000000049', '10000000-0000-4000-8000-000000000001', '20000000-0000-4000-8000-000000000006', 'flex: 1', 'flex-1', 'Let flex items share available space.', 'Learn how flex-grow, flex-shrink and basis combine in common shorthand patterns.', 7, 30, 35, false, 'lesson', 'Use flex sizing patterns.', array['Use flex 1', 'Understand grow', 'Understand shrink']),
